INSERT INTO `guides` VALUES ('06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Sofía','Mendez','sofia.mendez@email.com','Luxury Worked 5 years in five-star hotels before becoming an independent guide. Expert in exclusive experiences: private wine tastings, yachts and Michelin-starred restaurants.','1987-09-30','LUXURY','https://res.cloudinary.com/matthew1010100/image/upload/v1772470877/tfg/tvk6mq4pbp0tpusv11v6.webp'),('179f3a08-278d-4a8a-9d0c-75403d2f979f','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Isabella','Duarte','isabella.duarte@email.com','Relax Yoga and meditation instructor with experience leading retreats across Latin America. She designs experiences focused on digital detox and reconnecting with nature.','1993-06-19','RELAX','https://res.cloudinary.com/matthew1010100/image/upload/v1772471480/tfg/p0dvaxhp1nd9ny24wrde.webp'),('3efe963d-5f44-40cd-8214-d091ab3cdc51','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Valentina','Reyes','valentina.reyes@email.com','Adventure Passionate about hiking and mountain sports. She has spent 8 years organizing routes through the Pyrenees and the Picos de Europa. Certified in first aid and mountain rescue.','1991-03-14','ADVENTURE','https://res.cloudinary.com/matthew1010100/image/upload/v1772472811/tfg/cjaep1vfn0fscdlvhmdn.webp'),('801d9723-3424-49e2-bdd6-067a4194e76e','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Andrés','Figueroa','andres.figueroa@email.com','Adventure Professional diver and aquatic adventure guide. He has explored cenotes in Mexico, reefs in Honduras and coastlines in Galicia. PADI Master Scuba Diver certified.','1989-07-23','ADVENTURE','https://res.cloudinary.com/matthew1010100/image/upload/v1772471866/tfg/mzzyelisirxfgmjzdnvs.webp'),('818780af-f728-4b5d-84ea-241efdd7c89d','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Matías','Salazar','matias.salazar@email.com','Urban Historian and urban photographer. His walking tours through colonial cities and European capitals combine historical facts with the best Instagram photo spots.','1994-12-16','URBAN','https://res.cloudinary.com/matthew1010100/image/upload/v1772472625/tfg/rid53nt0gdmxjldazq1d.webp'),('844f0154-a67e-4ca7-a6c5-059e1816f228','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Lucía','Paredes','lucia.paredes@email.com','Urban Trained architect turned urban guide. She knows every hidden corner of Madrid and Barcelona. Her tours blend history, street art and nightlife.','1995-11-05','URBAN','https://res.cloudinary.com/matthew1010100/image/upload/v1772472176/tfg/nofsal1y3kewunmix6fh.webp'),('b50f60c3-5f2a-4fe5-8e55-6efded4918ce','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Diego','Navarro','diego.navarro@email.com','Relax Lover of slow living and wine tourism. He organizes getaways to charming villages, vineyards and countryside retreats. His motto: \'travel without rush, enjoy with calm\'.','1992-04-11','RELAX','https://res.cloudinary.com/matthew1010100/image/upload/v1772471355/tfg/ebdicflghlebellreurd.webp'),('cec08cfd-3f48-463c-8f2e-b5cd362d5f68','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Camila','Herrera','camila.herrera@email.com','Relax Specialist in wellness and thermal tourism. She has explored the best spas across Spain and Portugal. She loves designing itineraries that combine local gastronomy with rest and relaxation.','1988-08-27','RELAX','https://res.cloudinary.com/matthew1010100/image/upload/v1772472552/tfg/qranuma1hsew8xkzhutx.webp'),('d7ea5f25-f52b-4b5f-af16-3e84404c9227','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Mariana','Castillo','mariana.castillo@email.com','Adventure Former rafting and climbing instructor in Costa Rica. She now organizes adventure expeditions across Central America and southern Spain. Fluent in Spanish, English and Portuguese.','1990-01-02','ADVENTURE','https://res.cloudinary.com/matthew1010100/image/upload/v1772471123/tfg/zaqkcytmjvkfaw6sivjh.webp'),('d8d39325-d62d-4260-a08f-1542ce51d302','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','Miguel','Sanz','miguel30@gmail.com','Miguel is a 30-year-old from La Mancha, approachable and confident, with a simple and authentic style. He works as a city guide and is passionate about discovering and sharing the hidden stories of each city, enjoying every corner as if it were the first time.','1996-01-01','URBAN','https://res.cloudinary.com/matthew1010100/image/upload/v1772470058/tfg/kjokc9azlquqe7qavevn.webp');
/*!40000 ALTER TABLE `guides` ENABLE KEYS */;
