--
-- Table structure for table `trips`
--

DROP TABLE IF EXISTS `trips`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `trips` (
  `id` char(36) NOT NULL,
  `company_id` char(36) NOT NULL,
  `guide_id` char(36) NOT NULL,
  `title` varchar(255) NOT NULL,
  `trip_description` text NOT NULL,
  `continent` enum('Europe','America','Africa','Asia','Oceania') NOT NULL,
  `country` varchar(64) NOT NULL,
  `city` varchar(64) NOT NULL,
  `price` decimal(6,2) NOT NULL,
  `currency` enum('EUR','GBP','USD','CHF','CNY') NOT NULL,
  `stock` int NOT NULL,
  `start_date` date NOT NULL,
  `end_date` date NOT NULL,
  `rating` decimal(2,1) NOT NULL,
  `is_discount` tinyint(1) NOT NULL DEFAULT '0',
  `discount_percentage` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `company_id` (`company_id`),
  KEY `guide_id` (`guide_id`),
  CONSTRAINT `trips_ibfk_1` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `trips_ibfk_2` FOREIGN KEY (`guide_id`) REFERENCES `guides` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

