/*!40000 ALTER TABLE `trips` DISABLE KEYS */;
INSERT INTO `trips` VALUES ('00c2ab7b-699c-4a1b-86c6-a6100d195f96','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','844f0154-a67e-4ca7-a6c5-059e1816f228','Rebel Art','Discover Eastern Europe\'s most alternative and artistic side in Bratislava, a small capital full of surprises. You\'ll find quirky statues peeking out of manholes, giant murals on Soviet-era building facades, bars in ruins turned into art galleries and an emerging food scene that is putting Slovakia on the map. All of it on the banks of the Danube and at prices you won\'t find in any other European capital.','Europe','Slovakia','Bratislava',850.00,'EUR',45,'2026-10-05','2026-10-08',4.6,0,0),('0d737343-6139-427c-ab64-fa27500a1fd8','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','b50f60c3-5f2a-4fe5-8e55-6efded4918ce','Ancient Roots','Wander among centuries-old olive trees and savor the most authentic Cretan cuisine with the Mediterranean as your backdrop. Crete is the birthplace of the Mediterranean diet: you\'ll cook with local ingredients alongside village families, visit monasteries hidden in the mountains, swim in impossibly blue waters and understand why this island is one of the places on Earth where people live longest and best.','Europe','Greece','Chania',1300.00,'EUR',30,'2026-08-10','2026-08-16',4.4,0,0),('10357984-7aa1-4b80-a6f2-e1d85b0983b4','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Divine Coast','Sail the Amalfi Coast on a private yacht between pastel-colored villages clinging to cliffs, lemon trees perfuming the air and waters so intensely blue they seem unreal. You\'ll anchor in exclusive coves inaccessible by land, lunch on fresh pasta in Positano, toast with homemade limoncello in Ravello and watch sunsets that explain why the gods chose this coast as their home. The Mediterranean at its most sublime.','Europe','Italy','Amalfi',3500.00,'EUR',15,'2026-06-08','2026-06-14',4.1,0,0),('1178c22f-2193-44e8-92f8-81f197222ede','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','cec08cfd-3f48-463c-8f2e-b5cd362d5f68','Alpine Mirror','Wake up to the most magical lake in Europe, where a tiny church on an island seems to float in the morning mist. Bled is a fairytale place: you\'ll walk around the lake, climb to the medieval castle watching from above, try the famous cream cake and row a traditional pletna boat to the island to ring the wishing bell. Absolute peace nestled in the Julian Alps.','Europe','Slovenia','Bled',1250.00,'EUR',32,'2026-07-15','2026-07-19',4.1,0,0),('18e569fd-9532-45c7-b383-a9d2e8db7275','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','844f0154-a67e-4ca7-a6c5-059e1816f228','Urban Dolce Vita','Get lost in the streets of Rome\'s Trastevere among family-run trattorias, vespas parked on every corner and the golden light that makes Rome look like a living painting. Beyond the Colosseum and the Vatican, you\'ll discover neighborhoods like Testaccio and Monti, where Romans actually live, eat and enjoy. You\'ll taste the best carbonara of your life, sip an aperitivo watching the Tiber flow by and understand why all roads lead to Rome.','Europe','Italy','Rome',1200.00,'EUR',36,'2026-08-17','2026-08-21',4.9,0,0),('1b16baa3-fa93-44d7-8e83-163a91b7cdd9','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d7ea5f25-f52b-4b5f-af16-3e84404c9227','Tyrolean Vertigo','Tackle the most thrilling via ferratas in the Austrian Tyrol, suspended between sky and valley thousands of meters up with only a harness and your hands. You\'ll cross Tibetan bridges over abysses, scale walls fitted with iron rungs and reach summits with 360-degree Alpine views. In the afternoons, Innsbruck awaits with its craft beer and vibrant mix of Tyrolean culture and university life.','Europe','Austria','Innsbruck',1600.00,'EUR',20,'2026-08-27','2026-09-01',4.8,1,20),('1cf09b5b-4e61-49a8-b7f1-8337c70158a4','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d8d39325-d62d-4260-a08f-1542ce51d302','Canals and Secrets','Cycle along centuries-old canals, crooked houses and floating markets in Europe\'s most free-spirited and tolerant city. Amsterdam goes far beyond the clichés: you\'ll discover neighborhoods like Jordaan and De Pijp with their cozy cafés, independent galleries and design shops. You\'ll visit iconic museums, cruise the canals at sunset and understand why the Dutch have mastered the art of living on water like no one else.','Europe','Netherlands','Amsterdam',1200.00,'EUR',35,'2026-06-25','2026-06-29',4.7,0,0),('23f6e8f8-1e6b-44d2-a204-49879d53e2c0','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','844f0154-a67e-4ca7-a6c5-059e1816f228','Electric Nights','Experience Berlin\'s underground scene among giant murals, galleries in abandoned buildings and legendary clubs where the music doesn\'t stop until Monday. But Berlin is so much more than nightlife: you\'ll walk the Wall, visit world-class museums, eat street food from every culture on the planet and feel the energy of a city that reinvents itself every day without asking anyone\'s permission.','Europe','Germany','Berlin',1150.00,'EUR',38,'2026-06-11','2026-06-15',4.2,0,0),('257807dc-6e5a-4c2f-9e94-62c0458dfe0b','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','179f3a08-278d-4a8a-9d0c-75403d2f979f','Golden Hills','Taste the finest Tuscan wines among endless vineyards, solitary cypress trees and honey-colored sunsets that seem painted by Renaissance masters. You\'ll visit family-run wineries where winemaking traditions pass from generation to generation, wander through golden-stone medieval hilltowns and dine on handmade fresh pasta in agriturismos with sweeping valley views. A feast for all the senses.','Europe','Italy','Val d\'Orcia',1500.00,'EUR',28,'2026-07-01','2026-07-06',4.1,0,0),('2dda667b-105e-4de7-bab3-675a262b98a9','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','818780af-f728-4b5d-84ea-241efdd7c89d','Gothic Shadows','Explore the medieval alleyways of Barcelona\'s Gothic Quarter, where every corner hides a legend, a natural wine bar or a spot that feels straight out of a Carlos Ruiz Zafón novel. Beyond La Rambla you\'ll discover secret courtyards, hidden churches, contemporary art galleries and rooftop terraces with views of a skyline where old and new coexist in a fascinating, chaotic harmony.','Europe','Spain','Barcelona',1050.00,'EUR',40,'2026-06-04','2026-06-08',4.5,0,0),('2df65fe7-61f1-41e3-b0ad-cbb9c2fd7a48','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Star Flavor','Live a world-class gastronomic experience in San Sebastián, the city with the most Michelin stars per square meter on the planet. You\'ll hop from pintxo to pintxo through the Parte Vieja, visit centuries-old cider houses in the countryside, attend Basque cooking workshops and dine at restaurants where every dish is a work of art. All framed by La Concha bay, one of Europe\'s most beautiful urban beaches.','Europe','Spain','San Sebastián',2500.00,'EUR',20,'2026-09-28','2026-10-03',4.7,0,0),('32104f67-0876-4230-af6d-69a67a2102a5','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d7ea5f25-f52b-4b5f-af16-3e84404c9227','Rock and Sea','Climb limestone walls with the infinite blue of the Aegean at your feet in Kalymnos, the world capital of sport climbing. The island offers over 3,000 routes for all levels, and at the end of each day a swim in secluded coves and dinner at seaside tavernas with freshly caught fish await you. The perfect blend of physical challenge and carefree Mediterranean living.','Europe','Greece','Kalymnos',1450.00,'EUR',22,'2026-06-16','2026-06-21',4.9,0,0),('3b8bf5ec-53c2-409b-b06b-b915a945c34c','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','3efe963d-5f44-40cd-8214-d091ab3cdc51','Alpine Summits','Conquer the most breathtaking peaks of the Swiss Alps on an adventure that will test your endurance and reward you with views that take your breath away. You\'ll hike high-mountain trails between glaciers, turquoise lakes and alpine meadows, with stops at stone refuges where fondue tastes better than in any restaurant. Every step brings you closer to the sky.','Europe','Switzerland','Zermatt',1850.00,'EUR',20,'2026-06-02','2026-06-07',4.4,0,0),('3e7b55e8-a053-4960-8a3d-1973d1d31d7d','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d7ea5f25-f52b-4b5f-af16-3e84404c9227','Alpine Flight','Launch yourself into the void from the mountains of Interlaken and soar over emerald lakes and snow-capped peaks in Europe\'s paragliding capital. Beyond the flight, you\'ll explore glacial caves, bungee jump over the Aare river and hike panoramic trails between lakes Thun and Brienz. A short escape so intense you\'ll need a holiday from your holiday.','Europe','Switzerland','Interlaken',1900.00,'EUR',18,'2026-08-01','2026-08-04',4.0,0,0),('453c089f-de35-423e-8e4e-08d398ca2fd9','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','179f3a08-278d-4a8a-9d0c-75403d2f979f','Imperial Steam','Immerse yourself in Europe\'s most opulent thermal baths, where Art Nouveau architecture embraces steaming pools that Hungarians have enjoyed for centuries. You\'ll visit the legendary Széchenyi and Gellért, stroll along the Danube at sunset and discover that Budapest is a city made for the pleasure of the senses: great food, fine wines and a pace of life that invites you to stay.','Europe','Hungary','Budapest',1200.00,'EUR',35,'2026-06-01','2026-06-05',4.0,0,0),('47dbc514-8210-4380-acf5-436a7b2f193f','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','White Summit','Wake up facing the Matterhorn in a luxury chalet with a crackling fireplace, private spa and pristine snow as far as the eye can see. Zermatt in winter is paradise for discerning skiers: immaculate pistes, queue-free lifts, fondue in mountain refuges and the privilege of watching one of the world\'s most iconic mountains blush pink with every sunrise. Alpine luxury in its purest state.','Europe','Switzerland','Zermatt',3600.00,'EUR',16,'2026-12-01','2026-12-07',4.1,0,0),('4f6867cd-a8cb-4e26-9a4b-086566c820c2','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','818780af-f728-4b5d-84ea-241efdd7c89d','Rooftops of Paris','Discover the Paris tourists never see: secret rooftops with views of Montmartre, bistros where Parisians actually eat, hidden bookshops along the Seine and inner courtyards that are tiny oases of calm. You\'ll browse street markets, taste freshly baked croissants from century-old bakeries and walk through neighborhoods like Le Marais and Belleville, where the City of Light reveals its most authentic and vibrant face.','Europe','France','Paris',1400.00,'EUR',30,'2026-07-06','2026-07-10',4.4,0,0),('56331f5f-d591-4120-a320-ccedc8c70521','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Infinite Aegean','Watch the world\'s most famous sunset from an infinity pool suspended above Santorini\'s volcanic caldera, a glass of assyrtiko wine in hand and the Aegean stretching to infinity. You\'ll stay in a luxury cave suite carved into the white rock, dine at restaurants where modern Greek cuisine is served under the stars and wander through villages where every corner is a postcard the entire world envies.','Europe','Greece','Oia',3200.00,'EUR',16,'2026-06-22','2026-06-28',4.7,0,0),('57558f01-81c3-414e-8b9f-5288edcf84dd','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','cec08cfd-3f48-463c-8f2e-b5cd362d5f68','Silk Reflections','Glide gently across the waters of Italy\'s most elegant lake between dreamy villas, botanical gardens and pastel-colored villages shyly peering from the shore. Lake Como has been a refuge for artists, aristocrats and dreamers for centuries, and you\'ll understand why the moment you see the afternoon light bathe the surrounding mountains. Slowness, beauty and la dolce vita in its purest form.','Europe','Italy','Bellagio',1600.00,'EUR',22,'2026-08-24','2026-08-29',4.8,0,0),('609f5f68-120c-429d-a73f-f4154afdb865','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Dinner on the Walls','Savor exquisite Dalmatian haute cuisine on private terraces overlooking the Adriatic\'s most imposing medieval walls as the sun sinks behind the Elafiti Islands. Dubrovnik is a movie set — literally — and you\'ll experience it from its finest angles: exclusive dinners in converted palaces, private boat tours through crystalline waters, guided walks through the ancient city and sunsets that justify every cent of the trip.','Europe','Croatia','Dubrovnik',2600.00,'EUR',20,'2026-08-03','2026-08-08',4.0,0,0),('641090a6-334c-4bbb-8c93-34c749460e5d','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Secret Island','Escape to a private villa on the island of Hvar, where the only luxury is solitude, crystal-clear sea and lavender fields perfuming the Adriatic air. You\'ll sail between deserted islands, dine in exclusive konobas on freshly caught fish, visit boutique wineries and discover beaches accessible only by boat. Croatia at its most intimate and sophisticated, far from everything and close to paradise.','Europe','Croatia','Hvar',2900.00,'EUR',18,'2026-09-14','2026-09-19',4.6,1,15),('69586edb-0492-4d03-a2b6-7778e18a3a49','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','cec08cfd-3f48-463c-8f2e-b5cd362d5f68','Balearic Calm','Rest on secret white-sand coves with crystal-clear water in Menorca, the Balearic island that resists mass tourism. Away from the crowds, you\'ll discover beaches accessible only on foot through pine forests, whitewashed villages full of charm, lighthouses perched on cliff edges and a seafood cuisine that will have you ordering seconds of every dish. The perfect place to truly disconnect with the Mediterranean as your only soundtrack.','Europe','Spain','Menorca',1100.00,'EUR',40,'2026-06-22','2026-06-27',4.9,0,0),('6e1a3be4-44f4-4f0e-8b43-d6f8b13c5279','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','b50f60c3-5f2a-4fe5-8e55-6efded4918ce','Violet Soul','Lose yourself among endless lavender fields at sunset in the French Provence, where time stands still and the fragrance envelops everything. You\'ll browse village markets filled with cheese, honey and handmade soaps, visit medieval abbeys surrounded by cypress trees and dine al fresco under starry skies with a glass of rosé in hand. A journey that heals the soul without you even noticing.','Europe','France','Valensole',1350.00,'EUR',30,'2026-06-15','2026-06-20',4.8,0,0),('70e903d9-a187-4dfe-a921-7082b3ffc526','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','179f3a08-278d-4a8a-9d0c-75403d2f979f','Golden Cliffs','Watch unforgettable sunsets from sea caves and golden beaches in southern Portugal, where the Atlantic has sculpted the coast into arches, grottoes and rock formations that glow like gold at dusk. You\'ll hike coastal trails between fishing villages, taste cataplanas and Alentejo wines, and understand why the Algarve captivates everyone who visits without ever losing its authenticity.','Europe','Portugal','Lagos',1150.00,'EUR',35,'2026-09-01','2026-09-06',4.8,0,0),('759ceae3-e45c-409e-835f-202220dd2b0d','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','179f3a08-278d-4a8a-9d0c-75403d2f979f','English Charm','Rest in honey-colored stone cottages among rolling meadows, perfect hedgerows and villages where time seems to have stopped in the 18th century. The Cotswolds are the essence of the English countryside: you\'ll enjoy afternoon tea by the fireplace, visit secret gardens, walk through paths lined with sheep and discover centuries-old pubs where warm ale is served just as tradition demands.','Europe','United Kingdom','Cotswolds',1400.00,'EUR',26,'2026-08-03','2026-08-08',4.8,0,0),('80134a71-a1af-413b-9808-30c543063f58','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Crystal Train','Cross the Swiss Alps aboard the Glacier Express, the world\'s most famous panoramic train, while enjoying gourmet cuisine served in carriages with glass ceilings that frame snow-capped peaks, vertiginous bridges and picture-perfect valleys. Complete the experience with nights in luxury hotels in St. Moritz, horse-drawn carriage rides and fireside dinners in a setting that defines what it means to travel in style.','Europe','Switzerland','St. Moritz',3800.00,'EUR',15,'2026-07-20','2026-07-26',4.3,0,0),('82e2f5a1-1ac2-4009-9583-22e8b8ba9d5b','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d8d39325-d62d-4260-a08f-1542ce51d302','Golden Tram','Ride Lisbon\'s iconic yellow tram across its seven hills between tiled facades, breathtaking viewpoints and the distant sound of fado drifting through an open window. Lisbon is a city lived with your feet on its cobblestones and your eyes always looking up: you\'ll wander through Alfama, taste freshly baked pastéis de nata in Belém and toast with ginjinha in some corner of Bairro Alto.','Europe','Portugal','Lisbon',950.00,'EUR',45,'2026-07-20','2026-07-24',4.5,0,0),('856dc021-3e88-4dbe-b836-24ce2d21c415','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','cec08cfd-3f48-463c-8f2e-b5cd362d5f68','Danube Valley','Cruise along the Danube between terraced vineyards, baroque abbeys and Austrian villages that time seems to have forgotten. The Wachau Valley is a UNESCO World Heritage Site for a reason: every bend in the river reveals a ruined castle, a terrace of Grüner Veltliner grapes or a small tavern serving the best Apfelstrudel of your life. A river journey to be savored without haste.','Europe','Austria','Wachau Valley',1450.00,'EUR',28,'2026-10-05','2026-10-10',4.3,0,0),('881c7026-69fe-472e-84b3-9a7f8dfd0c92','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Monaco Skies','Soar by helicopter over the French Riviera, land in the world\'s most exclusive principality and live a few days where luxury knows no limit. You\'ll visit the Casino de Monte-Carlo, dine at restaurants overlooking a harbor packed with superyachts, walk the Formula 1 circuit on foot and enjoy an experience that blends glamour, adrenaline and the timeless elegance of the Côte d\'Azur at its absolute finest.','Europe','Monaco','Monte Carlo',4200.00,'EUR',15,'2026-08-17','2026-08-22',4.0,0,0),('8aab7222-760e-456d-8d47-cbe14f78508d','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','3efe963d-5f44-40cd-8214-d091ab3cdc51','Brave Lands','Ride through the Scottish Highlands between mist, dark lochs and heather-covered hills that seem pulled from another era. You\'ll cross valleys where only the wind can be heard, stop at centuries-old whisky distilleries and sleep in rustic lodges with crackling fireplaces. A trip for those who love mountain biking and landscapes that make you feel small before nature.','Europe','United Kingdom','Fort William',1650.00,'EUR',24,'2026-06-23','2026-06-28',4.1,0,0),('8b2a4f1b-40ec-4ccb-91a0-4c433dfec952','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','3efe963d-5f44-40cd-8214-d091ab3cdc51','Emerald River','Challenge the rapids of Europe\'s most beautiful river, whose impossibly green waters wind through pristine valleys in the Julian Alps. You\'ll combine rafting, kayaking and canyoning with hiking through pine-scented forests, and in the evening enjoy Slovenian cuisine in small family-run inns. A destination few know about but nobody forgets.','Europe','Slovenia','Soča Valley',1400.00,'EUR',22,'2026-08-07','2026-08-12',4.3,0,0),('9423bc17-f625-4ba6-93aa-62a932f65af6','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d7ea5f25-f52b-4b5f-af16-3e84404c9227','Titanic Waves','Face the biggest waves in Europe on the Portuguese coast where the Atlantic Ocean roars with legendary fury. Even if you don\'t ride the giant swells, you\'ll enjoy intense surf sessions, learn from local instructors and feel the raw power of the sea from the cliffs of São Miguel Arcanjo fort. Three days of pure salty adrenaline.','Europe','Portugal','Nazaré',1300.00,'EUR',16,'2026-07-08','2026-07-11',4.6,0,0),('9fd656ba-7dc1-410c-b1a1-f3f913456c5d','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','801d9723-3424-49e2-bdd6-067a4194e76e','Eternal Ice','Walk across ancient blue-ice glaciers on an expedition into Iceland\'s frozen heart. Equipped with crampons and ice axes, you\'ll explore ice caves, deep crevasses and formations that seem from another planet. Complete the experience with visits to monumental waterfalls, black sand beaches and nights in cabins overlooking volcanic landscapes that defy the imagination.','Europe','Iceland','Vatnajökull',2200.00,'EUR',16,'2026-08-18','2026-08-24',4.6,1,25),('a02af2bd-be09-4b89-b36a-9ac483e101c9','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Golden Bubbles','Enjoy exclusive champagne tastings in private châteaux surrounded by centuries-old vineyards in the region that invented the world\'s most celebrated sparkling wine. You\'ll tour underground cellars with miles of galleries where millions of bottles rest in silence, lunch at Michelin-starred restaurants and learn the art of sabrage from winemakers who have spent generations perfecting every vintage. A journey for discerning palates.','Europe','France','Épernay',2800.00,'EUR',18,'2026-07-06','2026-07-11',4.6,0,0),('a76474af-7df3-4c98-b2ad-215cba6a9c04','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','818780af-f728-4b5d-84ea-241efdd7c89d','Bohemian Clock','Walk through Prague\'s old town where every square, every bridge and every tower feels like a movie set that has survived wars and empires. You\'ll cross Charles Bridge at dawn with no tourists, get lost in the cobblestone alleys of the Jewish Quarter, discover underground breweries with centuries of history and gaze over the city from the world\'s largest castle as the Vltava river shimmers below.','Europe','Czech Republic','Prague',1000.00,'EUR',38,'2026-08-03','2026-08-07',4.3,1,10),('be46dd52-ac4b-43d7-85ac-25baa7866b82','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','818780af-f728-4b5d-84ea-241efdd7c89d','Colorful Facades','Stroll along Scandinavia\'s most cheerful harbor among Nyhavn\'s colorful houses, Nordic design shops and cafés where the concept of hygge comes to life. Copenhagen is a city best explored by bike: you\'ll pedal between palaces, Tivoli gardens, street food markets and creative districts like Nørrebro and Christiania. A city that proves you can be modern, sustainable and charming all at once.','Europe','Denmark','Copenhagen',1350.00,'EUR',30,'2026-09-21','2026-09-25',4.2,0,0),('bf8f866a-ee09-40aa-bbd9-b564a8a1f382','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','06b8ccf6-fd39-4dcf-8ee4-e8c27adce708','Medieval Fairytale','Sleep in a boutique hotel beside the medieval canals of Bruges, Belgium\'s most romantic city, where every cobblestone street feels pulled from a storybook. You\'ll taste handcrafted chocolates in century-old workshops, cruise canals on a private boat, visit Trappist breweries and dine at restaurants that transform Flemish cooking into a fine-dining experience. Medieval elegance with contemporary comfort.','Europe','Belgium','Bruges',2400.00,'EUR',22,'2026-09-07','2026-09-12',4.6,0,0),('c08c9109-b053-40b6-b4f7-040ac5aa165a','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','801d9723-3424-49e2-bdd6-067a4194e76e','Midnight Sun','Hike under a sky that never darkens along the most dramatic coastline in the Arctic. The Lofoten Islands offer white sand beaches backed by vertical mountains, fishing villages with red wooden cabins and a permanent golden light that turns every moment into a postcard. You\'ll trek coastal paths, fish for cod and sleep in traditional rorbuer perched above the water.','Europe','Norway','Lofoten Islands',2350.00,'EUR',15,'2026-07-22','2026-07-28',4.4,0,0),('c702cf4b-c2c6-408a-9aeb-d8bd65d0c4dc','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','b50f60c3-5f2a-4fe5-8e55-6efded4918ce','Northern Lights','Rest in a wooden cabin with a private sauna among snowy forests in Finnish Lapland, waiting for the spectacle of the aurora borealis dancing across the night sky. During the day you\'ll traverse white forests by sleigh, visit reindeer farms and sip hot chocolate by the fire. A winter retreat where the silence of the Arctic becomes the greatest luxury of all.','Europe','Finland','Rovaniemi',2100.00,'EUR',18,'2026-11-15','2026-11-21',4.2,0,0),('cda55d17-f81d-4475-8c86-b50d157558d2','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','3efe963d-5f44-40cd-8214-d091ab3cdc51','Emerald Gorge','Descend through limestone canyons, leap into turquoise pools and navigate whitewater rapids in the most impressive gorge in France. The Verdon is a paradise for canyoning, kayaking and climbing, surrounded by pine forests and lavender fields. After each day of adventure, Provence welcomes you with its cuisine and rosé wines at sunset.','Europe','France','Gorges du Verdon',1550.00,'EUR',20,'2026-07-14','2026-07-19',4.4,1,40),('d03448db-f91a-47af-acba-dce868827047','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','d8d39325-d62d-4260-a08f-1542ce51d302','Scottish Mist','Walk the Royal Mile under a fine rain that makes the cobblestones glisten and discover why Edinburgh is Europe\'s most mysterious and literary city. You\'ll visit underground crypts where ghost stories are told, climb Arthur\'s Seat for panoramic city views, explore centuries-old pubs where whisky flows generously and soak in the gothic atmosphere that inspired writers like Stevenson and J.K. Rowling.','Europe','United Kingdom','Edinburgh',1150.00,'EUR',32,'2026-09-07','2026-09-11',4.1,0,0),('dfe045a4-d371-4ff5-8abe-e854eaa41b1e','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','b50f60c3-5f2a-4fe5-8e55-6efded4918ce','Blue Lagoon','Relax in impossibly milky-blue geothermal waters as steam rises over a volcanic landscape that seems from another planet. Beyond the famous lagoon, you\'ll discover hidden hot springs, moss-covered lava fields and the raw beauty of the Reykjanes peninsula. A total reset for body and mind in one of the most singular places on Earth.','Europe','Iceland','Grindavík',1800.00,'EUR',25,'2026-07-08','2026-07-12',4.9,0,0),('f0dbd4fd-048f-42bc-badc-c7fc782f9709','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','801d9723-3424-49e2-bdd6-067a4194e76e','Needles of Dawn','Trek the most spectacular trails of the Italian Dolomites as sunrise paints the peaks in shades of pink, orange and gold. You\'ll walk between rock spires that resemble natural cathedrals, cross hanging bridges over ravines and rest in mountain refuges where homemade pasta is served with views no photograph can capture. A European trekking classic that never disappoints.','Europe','Italy','Cortina d\'Ampezzo',1750.00,'EUR',25,'2026-07-01','2026-07-06',4.4,0,0),('f5133f48-60df-4171-bf26-050c483d8fc8','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','844f0154-a67e-4ca7-a6c5-059e1816f228','Bazaar of the Senses','Dive into the perfect chaos of Istanbul, where Europe and Asia meet and every street is an explosion of aromas, colors and sounds. You\'ll haggle in the Grand Bazaar, sip tea by the Bosphorus, discover mosques that leave you speechless and dine on kebabs on terraces overlooking a skyline that has captivated travelers for millennia. A city you feel, not just visit.','Europe','Turkey','Istanbul',1100.00,'EUR',42,'2026-07-13','2026-07-18',4.6,1,30),('fb950666-7422-4bf9-834a-d3ae4660b314','5eb2c9e9-3d65-4e69-bc64-782d383b41c2','801d9723-3424-49e2-bdd6-067a4194e76e','Wild Fjords','Paddle through the crystal-clear waters of the Norwegian fjords, between cliffs rising hundreds of meters above you and waterfalls plunging straight into the sea. You\'ll camp on remote beaches accessible only by water, dine under a sky that barely darkens in summer and feel the immensity of a nature that hasn\'t changed in thousands of years. An expedition for those seeking silence and adrenaline in equal measure.','Europe','Norway','Geirangerfjord',2100.00,'EUR',18,'2026-06-09','2026-06-14',4.7,0,0);
